373→/** Update task status with subtask rollup */
374→export async function updateTaskStatus(input: {
375→  surreal: Surreal;
376→  workspaceRecord: RecordId<"workspace", string>;
377→  taskRecord: RecordId<"task", string>;
378→  status: string;
379→  notes?: string;
380→}): Promise<{ task_id: string; status: string; parent_status?: string }> {
381→  const now = new Date();
382→  const task = await input.surreal.select<TaskRow>(input.taskRecord);
383→  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
384→  if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
385→    throw new Error("task is outside the current workspace scope");
386→  }
387→
388→  await input.surreal.update(input.taskRecord).merge({
389→    status: input.status,
390→    updated_at: now,
391→  });
392→
393→  if (input.notes) {
394→    // Append note to description_entries
395→    const task = await input.surreal.select<{ description_entries?: Array<{ text: string; created_at: Date }> }>(input.taskRecord);
396→    const entries = task?.description_entries ?? [];
397→    entries.push({ text: input.notes, created_at: now });
398→    await input.surreal.update(input.taskRecord).merge({ description_entries: entries });
399→  }
400→
401→  // Check if this task has a parent (subtask_of) and compute rollup
402→  const [parentRows] = await input.surreal
403→    .query<[Array<{ out: RecordId<"task", string> }>]>(
404→      "SELECT out FROM subtask_of WHERE `in` = $task LIMIT 1;",
405→      { task: input.taskRecord },
406→    )
407→    .collect<[Array<{ out: RecordId<"task", string> }>]>();
408→
409→  let parentStatus: string | undefined;
410→
411→  if (parentRows.length > 0) {
412→    const parentRecord = parentRows[0].out;
413→    parentStatus = await computeSubtaskRollup(input.surreal, parentRecord);
414→  }
415→
416→  return {
417→    task_id: toRawId(input.taskRecord),
418→    status: input.status,
419→    ...(parentStatus ? { parent_status: parentStatus } : {}),
420→  };
421→}
