461→/** Log an implementation note on an entity */
462→export async function logImplementationNote(input: {
463→  surreal: Surreal;
464→  entityTable: string;
465→  entityId: string;
466→  note: string;
467→  filesChanged?: string[];
468→}): Promise<{ entity_id: string; note_added: boolean }> {
469→  const record = new RecordId(input.entityTable, input.entityId);
470→  const entity = await input.surreal.select<{ description_entries?: Array<{ text: string; source?: RecordId; created_at: Date }> }>(record);
471→
472→  if (!entity) throw new Error(`entity not found: ${input.entityTable}:${input.entityId}`);
473→
474→  const now = new Date();
475→  const entries = entity.description_entries ?? [];
476→  const noteText = input.filesChanged?.length
477→    ? `${input.note}\n\nFiles: ${input.filesChanged.join(", ")}`
478→    : input.note;
479→
480→  entries.push({ text: noteText, created_at: now });
481→
482→  await input.surreal.update(record).merge({
483→    description_entries: entries,
484→    updated_at: now,
485→  });
486→
487→  return { entity_id: `${input.entityTable}:${input.entityId}`, note_added: true };
488→}
