490→/** Create or finalize an agent session */
491→export async function createAgentSession(input: {
492→  surreal: Surreal;
493→  agent: string;
494→  workspaceRecord: RecordId<"workspace", string>;
495→  projectRecord?: RecordId<"project", string>;
496→  taskId?: string;
497→}): Promise<{ session_id: string }> {
498→  const now = new Date();
499→  const sessionRecord = new RecordId("agent_session", randomUUID());
500→
501→  await input.surreal.create(sessionRecord).content({
502→    agent: input.agent,
503→    started_at: now,
504→    workspace: input.workspaceRecord,
505→    created_at: now,
506→    ...(input.projectRecord ? { project: input.projectRecord } : {}),
507→    ...(input.taskId ? { task_id: new RecordId("task", requireRawId(input.taskId, "task_id")) } : {}),
508→  });
509→
510→  // If task-scoped, link session to task and auto-promote status
511→  if (input.taskId) {
512→    const taskRecord = new RecordId("task", requireRawId(input.taskId, "task_id"));
513→    const task = await input.surreal.select<TaskRow>(taskRecord);
514→    if (!task) {
515→      throw new Error(`task not found: ${input.taskId}`);
516→    }
517→    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
518→      throw new Error("task is outside the current workspace scope");
519→    }
520→    await input.surreal.update(taskRecord).merge({
521→      ...(task.status === "todo" || task.status === "ready"
522→        ? { status: "in_progress" }
523→        : {}),
524→      source_session: sessionRecord,
525→      updated_at: now,
526→    });
527→  }
528→
529→  return { session_id: toRawId(sessionRecord) };
530→}
