532→/** End an agent session with summary */
533→export async function endAgentSession(input: {
534→  surreal: Surreal;
535→  workspaceRecord: RecordId<"workspace", string>;
536→  sessionId: string;
537→  summary: string;
538→  decisionsMade?: string[];
539→  questionsAsked?: string[];
540→  tasksProgressed?: Array<{ task_id: string; from_status: string; to_status: string }>;
541→  filesChanged?: Array<{ path: string; change_type: string }>;
542→  observationsLogged?: string[];
543→}): Promise<{ session_id: string; ended: boolean }> {
544→  const now = new Date();
545→  const sessionRecord = new RecordId("agent_session", requireRawId(input.sessionId, "session_id"));
546→  const session = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(sessionRecord);
547→  if (!session) {
548→    throw new Error(`session not found: ${input.sessionId}`);
549→  }
550→  if ((session.workspace.id as string) !== (input.workspaceRecord.id as string)) {
551→    throw new Error("session is outside the current workspace scope");
552→  }
553→
554→  await input.surreal.update(sessionRecord).merge({
555→    ended_at: now,
556→    summary: input.summary,
557→    ...(input.decisionsMade?.length
558→      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", requireRawId(id, "decisions_made[]"))) }
559→      : {}),
560→    ...(input.questionsAsked?.length
561→      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", requireRawId(id, "questions_asked[]"))) }
562→      : {}),
563→    ...(input.tasksProgressed?.length
564→      ? {
565→          tasks_progressed: input.tasksProgressed.map((t) => ({
566→            task_id: new RecordId("task", requireRawId(t.task_id, "tasks_progressed[].task_id")),
567→            from_status: t.from_status,
