 13→import { readFileSync, writeFileSync, existsSync, rmSync, mkdirSync, copyFileSync, readdirSync, statSync } from "node:fs";
 14→import { resolve, dirname, basename } from "node:path";
 15→import { fileURLToPath, pathToFileURL } from "node:url";
 16→import { homedir, tmpdir } from "node:os";
