 18→
 19→// ─── Security module: graceful import from compiled build ───
 20→let security = null;
 21→try {
 22→  const __hookDir = dirname(fileURLToPath(import.meta.url));
 23→  const secPath = resolve(__hookDir, "..", "build", "security.js");
 24→  security = await import(pathToFileURL(secPath).href);
 25→} catch {
 26→  // Build not available — skip security checks, rely on existing routing
 27→}
 28→
 29→// ─── Manual recursive copy (avoids cpSync libuv crash on non-ASCII paths, Windows + Node 24) ───
 30→function copyDirSync(src, dest) {
 31→  mkdirSync(dest, { recursive: true });
 32→  for (const entry of readdirSync(src, { withFileTypes: true })) {
 33→    const srcPath = resolve(src, entry.name);
 34→    const destPath = resolve(dest, entry.name);
 35→    if (entry.isDirectory()) copyDirSync(srcPath, destPath);
 36→    else copyFileSync(srcPath, destPath);
 37→  }
 38→}
 39→
 40→// ─── Self-heal: rename dir to correct version, fix registry + hooks ───
 41→try {
 42→  const hookDir = dirname(fileURLToPath(import.meta.url));
 43→  const myRoot = resolve(hookDir, "..");
 44→  const myPkg = JSON.parse(readFileSync(resolve(myRoot, "package.json"), "utf-8"));
 45→  const myVersion = myPkg.version ?? "unknown";
 46→  const myDirName = basename(myRoot);
 47→  const cacheParent = dirname(myRoot);
 48→  const marker = resolve(tmpdir(), `context-mode-healed-${myVersion}`);
 49→
 50→  if (myVersion !== "unknown" && !existsSync(marker)) {
 51→    // 1. If dir name doesn't match version (e.g. "0.7.0" but code is "0.9.12"),
 52→    //    create correct dir, copy files, update registry + hooks
 53→    const correctDir = resolve(cacheParent, myVersion);
 54→    if (myDirName !== myVersion && !existsSync(correctDir)) {
 55→      copyDirSync(myRoot, correctDir);
 56→
 57→      // Create start.mjs in new dir if missing
 58→      const startMjs = resolve(correctDir, "start.mjs");
 59→      if (!existsSync(startMjs)) {
 60→        writeFileSync(startMjs, [
 61→          '#!/usr/bin/env node',
 62→          'import { existsSync } from "node:fs";',
 63→          'import { dirname, resolve } from "node:path";',
 64→          'import { fileURLToPath } from "node:url";',
 65→          'const __dirname = dirname(fileURLToPath(import.meta.url));',
 66→          'process.chdir(__dirname);',
 67→          'if (!process.env.CLAUDE_PROJECT_DIR) process.env.CLAUDE_PROJECT_DIR = process.cwd();',
 68→          'if (existsSync(resolve(__dirname, "server.bundle.mjs"))) {',
 69→          '  await import("./server.bundle.mjs");',
 70→          '} else if (existsSync(resolve(__dirname, "build", "server.js"))) {',
 71→          '  await import("./build/server.js");',
 72→          '}',
 73→        ].join("\n"), "utf-8");
 74→      }
 75→    }
 76→
 77→    const targetDir = existsSync(correctDir) ? correctDir : myRoot;
 78→
 79→    // 2. Update installed_plugins.json → point to correct version dir
 80→    //    Skip if not present (e.g. CI / non-Claude-Code environments)
 81→    const ipPath = resolve(homedir(), ".claude", "plugins", "installed_plugins.json");
 82→    if (existsSync(ipPath)) {
 83→      const ip = JSON.parse(readFileSync(ipPath, "utf-8"));
 84→      for (const [key, entries] of Object.entries(ip.plugins || {})) {
 85→        if (!key.toLowerCase().includes("context-mode")) continue;
 86→        for (const entry of entries) {
 87→          entry.installPath = targetDir;
 88→          entry.version = myVersion;
 89→          entry.lastUpdated = new Date().toISOString();
 90→        }
 91→      }
 92→      writeFileSync(ipPath, JSON.stringify(ip, null, 2) + "\n", "utf-8");
 93→    }
 94→
 95→    // 3. Update hook path in settings.json
 96→    const settingsPath = resolve(homedir(), ".claude", "settings.json");
 97→    try {
 98→      const settings = JSON.parse(readFileSync(settingsPath, "utf-8"));
 99→      const hooks = settings.hooks?.PreToolUse;
100→      if (Array.isArray(hooks)) {
101→        let changed = false;
102→        for (const entry of hooks) {
103→          for (const h of (entry.hooks || [])) {
104→            if (h.command?.includes("pretooluse.mjs") && !h.command.includes(targetDir)) {
105→              h.command = "node " + resolve(targetDir, "hooks", "pretooluse.mjs");
106→              changed = true;
107→            }
108→          }
109→        }
110→        if (changed) writeFileSync(settingsPath, JSON.stringify(settings, null, 2) + "\n", "utf-8");
111→      }
112→    } catch { /* skip settings update */ }
113→
114→    // 4. Nuke stale version dirs (keep only targetDir and current running dir)
115→    try {
116→      const keepDirs = new Set([basename(targetDir), myDirName]);
117→      for (const d of readdirSync(cacheParent)) {
118→        if (!keepDirs.has(d)) {
119→          try { rmSync(resolve(cacheParent, d), { recursive: true, force: true }); } catch { /* skip */ }
120→        }
121→      }
122→    } catch { /* skip */ }
123→
124→    writeFileSync(marker, Date.now().toString(), "utf-8");
125→  }
126→} catch { /* best effort — don't block hook */ }
