128→// Event-based flowing mode avoids two platform bugs:
129→// - `for await (process.stdin)` hangs on macOS when piped via spawnSync
130→// - `readFileSync(0)` throws EOF/EISDIR on Windows, EAGAIN on Linux
131→const raw = await new Promise((resolve, reject) => {
132→  let data = "";
133→  process.stdin.setEncoding("utf-8");
134→  process.stdin.on("data", (chunk) => { data += chunk; });
135→  process.stdin.on("end", () => resolve(data));
136→  process.stdin.on("error", reject);
137→  process.stdin.resume();
138→});
