151→    // Stage 1: Security check against user's deny/allow patterns.
152→    // Only act when an explicit pattern matched. When no pattern matches,
153→    // evaluateCommand returns { decision: "ask" } with no matchedPattern —
154→    // in that case fall through so other hooks and Claude Code's native engine can decide.
155→    if (security) {
156→      const policies = security.readBashPolicies(process.env.CLAUDE_PROJECT_DIR);
