158→        const result = security.evaluateCommand(command, policies);
159→        if (result.decision === "deny") {
160→          return {
161→            hookSpecificOutput: {
162→              hookEventName: "PreToolUse",
163→              permissionDecision: "deny",
164→              reason: `Blocked by security policy: matches deny pattern ${result.matchedPattern}`,
165→            },
166→          };
167→        }
168→        if (result.decision === "ask" && result.matchedPattern) {
169→          return {
170→            hookSpecificOutput: {
171→              hookEventName: "PreToolUse",
172→              permissionDecision: "ask",
173→            },
174→          };
175→        }
176→        // "allow" or no match → fall through to Stage 2
