189→          },
190→        },
191→      };
192→    }
193→
194→    // inline fetch (node -e, python -c, etc.) → replace with echo redirect
195→    if (
196→      /fetch\s*\(\s*['"](https?:\/\/|http)/i.test(command) ||
197→      /requests\.(get|post|put)\s*\(/i.test(command) ||
198→      /http\.(get|request)\s*\(/i.test(command)
