200→      return {
201→        hookSpecificOutput: {
202→          hookEventName: "PreToolUse",
203→          updatedInput: {
204→            command: 'echo "context-mode: Inline HTTP blocked. Use mcp__plugin_context-mode_context-mode__execute(language, code) to run HTTP calls in sandbox, or mcp__plugin_context-mode_context-mode__fetch_and_index(url, source) for web pages. Do NOT retry with Bash."',
