 32→
 33→export async function runMap(): Promise<void> {
 34→  const args = process.argv.slice(2); // ["map", "<dir>", "<type:id>", ...]
 35→  const dirArg = args[1];
 36→  const entityArg = args[2];
 37→
 38→  if (!dirArg || !entityArg) {
 39→    console.error("Usage: brain map <directory> <type:id> [--project <id>]");
 40→    console.error("Example: brain map ./services/auth project:abc123");
 41→    console.error("         brain map ./services/auth/oauth feature:def456 --project abc123");
 42→    console.error("Types: project, feature");
 43→    process.exit(1);
 44→  }
 45→
 46→  // Parse --project flag
 47→  const projectFlagIdx = args.indexOf("--project");
 48→  const projectId = projectFlagIdx !== -1 ? args[projectFlagIdx + 1] : undefined;
 49→  if (projectFlagIdx !== -1 && !projectId) {
 50→    console.error("--project requires a project ID");
 51→    process.exit(1);
 52→  }
 53→
 54→  // Validate directory
 55→  const dir = resolve(dirArg);
 56→  if (!existsSync(dir) || !statSync(dir).isDirectory()) {
 57→    console.error(`Not a directory: ${dir}`);
 58→    process.exit(1);
 59→  }
 60→
 61→  // Parse entity reference
 62→  const colonIdx = entityArg.indexOf(":");
 63→  if (colonIdx === -1) {
 64→    console.error("Entity must be in type:id format (e.g. project:abc123)");
 65→    process.exit(1);
 66→  }
 67→
 68→  const entityType = entityArg.slice(0, colonIdx) as SupportedType;
 69→  const entityRawId = entityArg.slice(colonIdx + 1);
 70→
