 77→    process.exit(1);
 78→  }
 79→
 80→  // Validate entity exists in workspace
 81→  const config = await requireConfig();
 82→  const client = new BrainHttpClient(config);
 83→
 84→  let detail: EntityDetail;
 85→  try {
 86→    detail = (await client.getEntityDetail(entityArg)) as EntityDetail;
 87→  } catch (error) {
 88→    console.error(`Entity not found or not in workspace: ${entityArg}`);
 89→    console.error(error instanceof Error ? error.message : String(error));
 90→    process.exit(1);
 91→  }
