101→// ---------------------------------------------------------------------------
102→// brain unmap <dir>
103→// ---------------------------------------------------------------------------
104→
105→export async function runUnmap(): Promise<void> {
106→  const dirArg = process.argv[3];
107→
108→  if (!dirArg) {
109→    console.error("Usage: brain unmap <directory>");
110→    process.exit(1);
111→  }
112→
113→  const dir = resolve(dirArg);
114→  const claudeMdPath = join(dir, "CLAUDE.md");
115→
116→  if (!existsSync(claudeMdPath)) {
117→    console.error(`No CLAUDE.md found in ${dir}`);
118→    process.exit(1);
119→  }
120→
121→  const file = Bun.file(claudeMdPath);
122→  let content = await file.text();
123→
124→  const startIdx = content.indexOf(MAP_MARKER_START);
125→  const endIdx = content.indexOf(MAP_MARKER_END);
