144→};
145→
146→type RecentChangeRow = {
147→  entity_type: string;
148→  entity_name: string;
149→  change_type: string;
150→  changed_at: Date | string;
151→};
152→
153→function toIso(value: Date | string | undefined): string {
154→  if (!value) return "";
155→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
156→}
