236→// ===========================================================================
237→// 2. Project Context (full project context, project_id required)
238→// ===========================================================================
239→
240→/** Build a full project context packet (decisions, tasks, questions, observations, suggestions) */
241→export async function buildProjectContext(input: {
242→  surreal: Surreal;
243→  workspaceRecord: RecordId<"workspace", string>;
244→  workspaceName: string;
245→  projectRecord: RecordId<"project", string>;
246→  taskId?: string;
247→  since?: string;
248→  excludeSessionId?: string;
249→}): Promise<ContextPacket> {
250→  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
251→
252→  const project = await surreal.select<ProjectRow>(projectRecord);
253→  if (!project) {
254→    throw new Error(`project not found: ${projectRecord.id}`);
255→  }
256→
257→  const projectEntitiesQuery = `
258→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
259→
260→    SELECT id, summary, status, rationale, decided_at, category, priority
261→    FROM decision
262→    WHERE workspace = $workspace AND id IN $project_entity_ids
263→    ORDER BY created_at DESC LIMIT 50;
264→
265→    SELECT id, title, status, priority, category, description, source_session
266→    FROM task
267→    WHERE workspace = $workspace AND id IN $project_entity_ids
268→    ORDER BY created_at DESC LIMIT 50;
269→
270→    SELECT id, text, status, context, priority
271→    FROM question
272→    WHERE workspace = $workspace AND id IN $project_entity_ids
273→    ORDER BY created_at DESC LIMIT 30;
274→
275→    SELECT id, text, severity, status, category, observation_type
276→    FROM observation
277→    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
278→    ORDER BY created_at DESC LIMIT 20;
279→
280→    SELECT id, text, category, rationale, confidence, status, suggested_by, created_at
281→    FROM suggestion
282→    WHERE workspace = $workspace AND status IN ["pending", "deferred"]
283→    ORDER BY confidence DESC, created_at DESC LIMIT 15;
284→  `;
285→
286→  const results = await surreal
287→    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[], SuggestionRow[]]>(projectEntitiesQuery, {
288→      project: projectRecord,
289→      workspace: workspaceRecord,
290→    })
291→    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[], SuggestionRow[]]>();
292→
293→  const [, decisionRows, taskRows, questionRows, observationRows, suggestionRows] = results;
294→
295→  // Categorize decisions by status
296→  const confirmed: DecisionContext[] = [];
297→  const provisional: DecisionContext[] = [];
298→  const contested: DecisionContext[] = [];
299→
300→  for (const d of decisionRows) {
301→    const ctx: DecisionContext = {
302→      id: toRawId(d.id),
303→      summary: d.summary,
304→      status: d.status,
305→      ...(d.rationale ? { rationale: d.rationale } : {}),
306→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
307→      ...(d.category ? { category: d.category } : {}),
308→      ...(d.priority ? { priority: d.priority } : {}),
309→    };
310→
311→    if (d.status === "contested") {
312→      contested.push(ctx);
313→    } else if (d.status === "provisional" || d.status === "inferred") {
314→      provisional.push(ctx);
315→    } else if (d.status === "confirmed") {
316→      confirmed.push(ctx);
317→    }
318→  }
319→
320→  const activeTasks: TaskContext[] = taskRows
321→    .filter((t) => t.status !== "done" && t.status !== "completed")
322→    .map((t) => ({
323→      id: toRawId(t.id),
324→      title: t.title,
325→      status: t.status,
326→      ...(t.priority ? { priority: t.priority } : {}),
327→      ...(t.category ? { category: t.category } : {}),
328→      ...(t.source_session ? { source_session: toRawId(t.source_session) } : {}),
329→    }));
330→
331→  const openQuestions: QuestionContext[] = questionRows
332→    .filter((q) => q.status !== "answered" && q.status !== "resolved")
333→    .map((q) => ({
334→      id: toRawId(q.id),
335→      text: q.text,
336→      status: q.status,
337→      ...(q.context ? { context: q.context } : {}),
338→      ...(q.priority ? { priority: q.priority } : {}),
339→    }));
340→
341→  const observations: ObservationContext[] = observationRows.map((o) => ({
342→    id: toRawId(o.id),
343→    text: o.text,
344→    severity: o.severity,
345→    status: o.status,
346→    ...(o.category ? { category: o.category } : {}),
347→    ...(o.observation_type ? { observation_type: o.observation_type } : {}),
348→  }));
349→
350→  const pendingSuggestions: SuggestionContext[] = suggestionRows.map((s) => ({
351→    id: toRawId(s.id),
352→    text: s.text,
353→    category: s.category,
354→    rationale: s.rationale,
355→    confidence: s.confidence,
356→    status: s.status,
357→    suggested_by: s.suggested_by,
358→    created_at: toIso(s.created_at),
359→  }));
360→
361→  const activeSessions = await loadActiveSessions(surreal, workspaceRecord, projectRecord, input.excludeSessionId);
362→
363→  const recentChanges: RecentChangeContext[] = input.since
364→    ? await loadRecentChanges(surreal, workspaceRecord, projectRecord, input.since)
365→    : [];
366→
367→  let taskScope: TaskScopeContext | undefined;
368→  if (taskId) {
369→    taskScope = await buildTaskScope(surreal, workspaceRecord, taskId);
370→  }
371→
372→  return {
373→    workspace: { id: workspaceRecord.id as string, name: workspaceName },
374→    project: {
375→      id: projectRecord.id as string,
376→      name: project.name,
377→      status: project.status,
378→      ...(project.description ? { description: project.description } : {}),
379→    },
380→    ...(taskScope ? { task_scope: taskScope } : {}),
381→    decisions: { confirmed, provisional, contested },
382→    active_tasks: activeTasks,
383→    open_questions: openQuestions,
384→    recent_changes: recentChanges,
385→    observations,
386→    pending_suggestions: pendingSuggestions,
387→    active_sessions: activeSessions,
388→  };
389→}
390→
391→// ===========================================================================
392→// 3. Task Context (task-focused, task_id required, project resolved from graph)
393→// ===========================================================================
394→
395→/** Build task-focused context: task subgraph + project hot items */
396→export async function buildTaskContext(input: {
397→  surreal: Surreal;
398→  workspaceRecord: RecordId<"workspace", string>;
399→  workspaceName: string;
400→  taskId: string;
401→  excludeSessionId?: string;
402→}): Promise<TaskContextPacket> {
403→  const { surreal, workspaceRecord, workspaceName, taskId } = input;
404→
405→  const taskRecord = new RecordId("task", taskId);
406→  const task = await surreal.select<TaskRow & { workspace: RecordId<"workspace", string> }>(taskRecord);
407→  if (!task) {
408→    throw new Error(`task not found: ${taskId}`);
409→  }
410→  if ((task.workspace.id as string) !== (workspaceRecord.id as string)) {
411→    throw new Error(`task not in workspace: ${taskId}`);
412→  }
413→
414→  // Resolve project from belongs_to edge
415→  const [projectEdges] = await surreal
416→    .query<[Array<{ out: RecordId<"project", string> }>]>(
417→      `SELECT out FROM belongs_to WHERE \`in\` = $task AND record::tb(out) = "project" LIMIT 1;`,
418→      { task: taskRecord },
419→    )
420→    .collect<[Array<{ out: RecordId<"project", string> }>]>();
421→
422→  let projectInfo: { id: string; name: string; status: string };
423→  let projectRecord: RecordId<"project", string> | undefined;
424→
425→  if (projectEdges.length > 0) {
426→    projectRecord = projectEdges[0].out;
427→    const project = await surreal.select<ProjectRow>(projectRecord);
428→    if (project) {
429→      projectInfo = { id: toRawId(project.id), name: project.name, status: project.status };
430→    } else {
431→      projectInfo = { id: toRawId(projectRecord), name: "unknown", status: "unknown" };
432→    }
433→  } else {
434→    projectInfo = { id: "unassigned", name: "unassigned", status: "unknown" };
435→  }
436→
437→  const taskScope = await buildTaskScope(surreal, workspaceRecord, taskId);
438→  const hotItems = await loadHotItems(surreal, workspaceRecord, projectRecord);
439→  const activeSessions = await loadActiveSessions(surreal, workspaceRecord, projectRecord, input.excludeSessionId);
440→
441→  return {
442→    workspace: { id: workspaceRecord.id as string, name: workspaceName },
443→    project: projectInfo,
444→    task_scope: taskScope,
445→    hot_items: hotItems,
446→    active_sessions: activeSessions,
447→  };
448→}
