450→// ===========================================================================
451→// Shared helpers
452→// ===========================================================================
453→
454→/** Load hot items: contested decisions, open observations, pending suggestions */
455→async function loadHotItems(
456→  surreal: Surreal,
457→  workspaceRecord: RecordId<"workspace", string>,
458→  projectRecord?: RecordId<"project", string>,
459→): Promise<HotItems> {
460→  // When project-scoped, filter decisions via belongs_to
461→  const decisionFilter = projectRecord
462→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
463→    : "";
464→
465→  const hotQuery = `
466→    SELECT id, summary
467→    FROM decision
468→    WHERE workspace = $workspace AND status = "contested" ${decisionFilter}
469→    ORDER BY updated_at DESC LIMIT 10;
470→
471→    SELECT id, text, severity, category
472→    FROM observation
473→    WHERE workspace = $workspace AND status IN ["open", "acknowledged"] AND severity IN ["warning", "conflict"]
474→    ORDER BY created_at DESC LIMIT 10;
475→
476→    SELECT id, text, category, confidence
477→    FROM suggestion
478→    WHERE workspace = $workspace AND status = "pending"
479→    ORDER BY confidence DESC, created_at DESC LIMIT 5;
480→  `;
481→
482→  const [contestedDecisions, hotObservations, hotSuggestions] = await surreal
483→    .query<[ContestedDecisionRow[], HotObservationRow[], HotSuggestionRow[]]>(hotQuery, {
484→      workspace: workspaceRecord,
485→      ...(projectRecord ? { project: projectRecord } : {}),
486→    })
487→    .collect<[ContestedDecisionRow[], HotObservationRow[], HotSuggestionRow[]]>();
488→
489→  return {
490→    contested_decisions: contestedDecisions.map((d) => ({
491→      id: toRawId(d.id),
492→      summary: d.summary,
493→    })),
494→    open_observations: hotObservations.map((o) => ({
495→      id: toRawId(o.id),
496→      text: o.text,
497→      severity: o.severity,
498→      ...(o.category ? { category: o.category } : {}),
499→    })),
500→    pending_suggestions: hotSuggestions.map((s) => ({
501→      id: toRawId(s.id),
502→      text: s.text,
503→      category: s.category,
504→      confidence: s.confidence,
505→    })),
506→  };
507→}
508→
509→/** Build task-scoped context: subtasks, parent feature, siblings, dependencies, related sessions */
510→async function buildTaskScope(
511→  surreal: Surreal,
512→  workspaceRecord: RecordId<"workspace", string>,
513→  taskId: string,
514→): Promise<TaskScopeContext> {
515→  const taskRecord = new RecordId("task", taskId);
516→  const task = await surreal.select<TaskRow & { workspace: RecordId<"workspace", string> }>(taskRecord);
517→  if (!task) {
518→    throw new Error(`task not found: ${taskId}`);
519→  }
520→  if ((task.workspace.id as string) !== (workspaceRecord.id as string)) {
521→    throw new Error(`task not in workspace: ${taskId}`);
522→  }
523→
524→  const taskScopeQuery = `
525→    SELECT id, title, status
526→    FROM task
527→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
528→    ORDER BY created_at ASC;
529→
530→    SELECT id, name, description
531→    FROM feature
532→    WHERE id IN (SELECT VALUE \`in\` FROM has_task WHERE out = $task)
533→    LIMIT 1;
534→
535→    SELECT id, title, status
536→    FROM task
537→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
538→
539→    SELECT id, agent, ended_at, summary
540→    FROM agent_session
541→    WHERE task_id = $task AND ended_at != NONE
542→    ORDER BY ended_at DESC LIMIT 5;
543→  `;
544→
545→  const results = await surreal
546→    .query<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>(taskScopeQuery, {
547→      task: taskRecord,
548→    })
549→    .collect<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>();
550→
551→  const [subtaskRows, featureRows, dependencyRows, sessionRows] = results;
552→
553→  const parentFeature = featureRows.length > 0
554→    ? {
555→        id: toRawId(featureRows[0].id),
556→        name: featureRows[0].name,
557→        ...(featureRows[0].description ? { description: featureRows[0].description } : {}),
558→      }
559→    : undefined;
560→
561→  let siblingTasks: { id: string; title: string; status: string; source_session?: string }[] = [];
562→  if (parentFeature && featureRows.length > 0) {
563→    const [siblingRows] = await surreal
564→      .query<[TaskRow[]]>(
565→        `SELECT id, title, status, source_session FROM task
566→         WHERE id IN (SELECT VALUE out FROM has_task WHERE \`in\` = $feature)
567→           AND id != $task
568→         ORDER BY created_at ASC LIMIT 20;`,
569→        { feature: featureRows[0].id, task: taskRecord },
570→      )
571→      .collect<[TaskRow[]]>();
572→
573→    siblingTasks = siblingRows.map((t) => ({
574→      id: toRawId(t.id),
575→      title: t.title,
576→      status: t.status,
577→      ...(t.source_session ? { source_session: toRawId(t.source_session) } : {}),
578→    }));
579→  }
580→
581→  return {
582→    task: {
583→      id: toRawId(task.id),
584→      title: task.title,
585→      ...(task.description ? { description: task.description } : {}),
586→      status: task.status,
587→      ...(task.category ? { category: task.category } : {}),
588→    },
589→    subtasks: subtaskRows.map((s) => ({
590→      id: toRawId(s.id),
591→      title: s.title,
592→      status: s.status,
593→    })),
594→    parent_feature: parentFeature,
595→    sibling_tasks: siblingTasks,
596→    dependencies: dependencyRows.map((d) => ({
597→      id: toRawId(d.id),
598→      title: d.title,
599→      status: d.status,
600→    })),
601→    related_sessions: sessionRows.map((s) => ({
602→      id: toRawId(s.id),
603→      agent: s.agent,
604→      ended_at: toIso(s.ended_at),
605→      summary: s.summary ?? "",
606→    })),
607→  };
608→}
609→
610→/** Load active agent sessions, optionally scoped to a project */
611→async function loadActiveSessions(
612→  surreal: Surreal,
613→  workspaceRecord: RecordId<"workspace", string>,
614→  projectRecord?: RecordId<"project", string>,
615→  excludeSessionId?: string,
616→): Promise<ActiveSessionContext[]> {
617→  const excludeRecord = excludeSessionId
618→    ? new RecordId("agent_session", excludeSessionId)
619→    : new RecordId("agent_session", "__none__");
620→
621→  const projectFilter = projectRecord ? "AND project = $project" : "";
622→  const [sessionRows] = await surreal
623→    .query<[ActiveAgentSessionRow[]]>(
624→      `SELECT id, agent, started_at, task_id
625→       FROM agent_session
626→       WHERE workspace = $workspace ${projectFilter} AND ended_at = NONE AND id != $exclude
627→       ORDER BY started_at DESC LIMIT 10;`,
628→      { workspace: workspaceRecord, ...(projectRecord ? { project: projectRecord } : {}), exclude: excludeRecord },
629→    )
630→    .collect<[ActiveAgentSessionRow[]]>();
631→
632→  if (sessionRows.length === 0) return [];
633→
634→  const sessionIds = sessionRows.map((s) => s.id);
635→
636→  const [observationRows] = await surreal
637→    .query<[SessionObservationRow[]]>(
638→      `SELECT id, text, severity, source_session FROM observation
639→       WHERE source_session IN $sessions
640→         AND status IN ["open", "acknowledged"];`,
641→      { sessions: sessionIds },
642→    )
643→    .collect<[SessionObservationRow[]]>();
644→
645→  const taskIds = sessionRows
646→    .filter((s) => s.task_id)
647→    .map((s) => s.task_id!);
648→
649→  let taskTitles: Map<string, string> = new Map();
650→  if (taskIds.length > 0) {
651→    const [taskRows] = await surreal
652→      .query<[Array<{ id: RecordId<"task", string>; title: string }>]>(
653→        `SELECT id, title FROM task WHERE id IN $tasks;`,
654→        { tasks: taskIds },
655→      )
656→      .collect<[Array<{ id: RecordId<"task", string>; title: string }>]>();
657→    taskTitles = new Map(taskRows.map((t) => [toRawId(t.id), t.title]));
658→  }
659→
660→  const obsBySession = new Map<string, Array<{ id: string; text: string; severity: string }>>();
661→  for (const o of observationRows) {
662→    const sessionKey = toRawId(o.source_session);
663→    const arr = obsBySession.get(sessionKey) ?? [];
664→    arr.push({ id: toRawId(o.id), text: o.text, severity: o.severity });
665→    obsBySession.set(sessionKey, arr);
666→  }
667→
668→  const decisionsBySession = new Map<string, Array<{ id: string; summary: string }>>();
669→  for (const session of sessionRows) {
670→    const sessionKey = toRawId(session.id);
671→    const [decisionRows] = await surreal
672→      .query<[Array<{ id: RecordId<"decision", string>; summary: string }>]>(
673→        `SELECT id, summary FROM decision
674→         WHERE id IN (SELECT VALUE out FROM produced WHERE \`in\` = $session)
675→           AND status = "provisional";`,
676→        { session: session.id },
677→      )
678→      .collect<[Array<{ id: RecordId<"decision", string>; summary: string }>]>();
679→
680→    decisionsBySession.set(
681→      sessionKey,
682→      decisionRows.map((d) => ({ id: toRawId(d.id), summary: d.summary })),
683→    );
684→  }
685→
686→  return sessionRows.map((s) => {
687→    const sessionKey = toRawId(s.id);
688→    const taskId = s.task_id ? toRawId(s.task_id) : undefined;
689→    return {
690→      id: sessionKey,
691→      agent: s.agent,
692→      started_at: toIso(s.started_at),
693→      ...(taskId && taskTitles.has(taskId)
694→        ? { task: { id: taskId, title: taskTitles.get(taskId)! } }
695→        : {}),
696→      provisional_decisions: decisionsBySession.get(sessionKey) ?? [],
697→      observations: obsBySession.get(sessionKey) ?? [],
698→    };
699→  });
700→}
701→
702→/** Load entities changed since a timestamp (project-scoped) */
703→async function loadRecentChanges(
704→  surreal: Surreal,
705→  workspaceRecord: RecordId<"workspace", string>,
706→  projectRecord: RecordId<"project", string>,
707→  since: string,
708→): Promise<RecentChangeContext[]> {
709→  const sinceDate = new Date(since);
710→
711→  const query = `
712→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
713→
714→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
715→    FROM decision
716→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
717→    ORDER BY updated_at DESC LIMIT 20;
718→
719→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
720→    FROM task
721→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
722→    ORDER BY updated_at DESC LIMIT 20;
723→
724→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
725→    FROM question
726→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
727→    ORDER BY updated_at DESC LIMIT 20;
728→
