      asked_by: "code-agent",
      ...(body.options?.length ? { options: body.options } : {}),
      ...(blockingTaskId ? { blocking_task: new RecordId("task", blockingTaskId) } : {}),
    });

    logInfo("mcp.question.created", "Question created via MCP", {
